render.css:
.fg-root {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  padding: 9px 14px 9px 11px;
  position: relative;
  isolation: isolate;
  color: #f7f4da;
}

.fg-shell {
  position: absolute;
  inset: -2px;
  z-index: 0;
  overflow: hidden;
  border: 1.5px solid rgba(220, 228, 166, .72);
  border-radius: 13px;
  background: #252b24;
  box-shadow:
    0 0 0 1px rgba(35, 42, 32, .88),
    3px 4px 0 rgba(25, 30, 24, .72),
    0 12px 24px -16px rgba(87, 110, 63, .8),
    inset 0 1px 0 rgba(255, 255, 222, .16);
  transition: border-color .3s ease, box-shadow .3s ease;
}

.fg-shell::before {
  content: '';
  position: absolute;
  inset: -58% -20%;
  transform-origin: 20% 50%;
  background: conic-gradient(
    from 278deg at 20% 50%,
    transparent 0deg 286deg,
    rgba(208, 231, 108, .04) 300deg,
    rgba(208, 231, 108, .68) 316deg,
    rgba(244, 214, 92, .24) 330deg,
    transparent 348deg 360deg
  );
  animation: radar-turn 8s linear infinite;
}

.fg-shell::after {
  content: '';
  position: absolute;
  inset: 3px;
  z-index: 1;
  border: 1px solid rgba(220, 228, 166, .16);
  border-radius: 10px;
  background:
    linear-gradient(90deg, rgba(234, 241, 171, .07) 1px, transparent 1px),
    linear-gradient(0deg, rgba(234, 241, 171, .05) 1px, transparent 1px),
    radial-gradient(110% 180% at 8% 50%, rgba(121, 157, 78, .24), transparent 46%),
    linear-gradient(145deg, rgba(47, 59, 43, .92), rgba(27, 33, 28, .94));
  background-size: 16px 16px, 16px 16px, auto, auto;
}

.fg-deco {
  position: absolute;
  inset: -2px;
  z-index: 2;
  overflow: hidden;
  border-radius: 13px;
  pointer-events: none;
}

.fg-deco::before {
  content: '';
  position: absolute;
  top: -30%;
  left: 0;
  width: 28%;
  height: 160%;
  background: linear-gradient(100deg, transparent 0%, rgba(245, 251, 190, .05) 34%, rgba(230, 242, 127, .82) 50%, rgba(245, 251, 190, .08) 66%, transparent 100%);
  transform: translateX(-230%) skewX(-16deg);
  animation: scan-pass 4.6s ease-in-out infinite;
}

.fg-deco::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background:
    linear-gradient(90deg, rgba(224, 235, 147, .78) 0 2px, transparent 2px 9px, rgba(224, 235, 147, .78) 9px 11px, transparent 11px) left 9px top 8px / 11px 2px no-repeat,
    linear-gradient(0deg, rgba(224, 235, 147, .78) 0 2px, transparent 2px 9px, rgba(224, 235, 147, .78) 9px 11px, transparent 11px) left 9px top 8px / 2px 11px no-repeat,
    linear-gradient(90deg, rgba(225, 96, 69, .88) 0 3px, transparent 3px) right 11px bottom 9px / 18px 2px no-repeat,
    radial-gradient(2px 2px at 82% 26%, rgba(249, 226, 108, .98), transparent 70%),
    radial-gradient(1.5px 1.5px at 91% 70%, rgba(231, 103, 77, .94), transparent 70%),
    radial-gradient(1.5px 1.5px at 65% 82%, rgba(219, 235, 143, .9), transparent 70%);
  opacity: .76;
  animation: signal-blink 2.8s ease-in-out infinite alternate;
}

.fg-avatar {
  position: relative;
  z-index: 3;
  display: flex;
  align-items: center;
  justify-content: center;
  width: var(--fg-avatar, 40px);
  height: var(--fg-avatar, 40px);
  overflow: hidden;
  border: 2px solid #e0e99c;
  border-radius: 50%;
  background:
    linear-gradient(rgba(215, 232, 123, .16) 1px, transparent 1px),
    linear-gradient(90deg, rgba(215, 232, 123, .16) 1px, transparent 1px),
    radial-gradient(circle at 38% 32%, #a8c95f, #4c7444 54%, #273c2d 100%);
  background-size: 8px 8px, 8px 8px, auto;
  box-shadow:
    0 0 0 3px rgba(22, 31, 24, .82),
    0 0 0 4px rgba(212, 229, 133, .28),
    inset 0 0 12px rgba(238, 249, 177, .22);
  transition: transform .3s cubic-bezier(.22, 1, .36, 1), box-shadow .3s ease;
}

.fg-avatar::before {
  content: '';
  position: absolute;
  inset: 14%;
  border: 1px solid rgba(239, 247, 177, .62);
  border-radius: 50%;
  animation: lens-pulse 2.4s ease-in-out infinite;
}

.fg-avatar::after {
  content: '';
  position: absolute;
  inset: 48% 9%;
  height: 1px;
  background: rgba(231, 242, 153, .7);
  box-shadow: 0 -10px 0 rgba(231, 242, 153, .22), 0 10px 0 rgba(231, 242, 153, .22);
  opacity: .62;
}

.fg-glyph {
  position: relative;
  z-index: 1;
  color: #fffbdc;
  font-weight: 900;
  font-size: calc(var(--fg-avatar, 40px) * .38);
  letter-spacing: -.04em;
  text-shadow: 0 1px 2px rgba(24, 38, 24, .72), 0 0 8px rgba(235, 246, 153, .42);
  animation: glyph-steady 3.2s ease-in-out infinite;
}

.fg-meta {
  position: relative;
  z-index: 3;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.fg-name {
  color: #f8f6d9;
  font-size: var(--fg-name-size, 16px);
  font-weight: 850;
  line-height: 1.15;
  text-shadow: 0 1px 6px rgba(12, 18, 13, .72);
}

.fg-time {
  margin-top: 3px;
  color: rgba(214, 226, 166, .72);
  font-size: 11px;
  letter-spacing: .04em;
}

.fg-root:hover .fg-shell {
  border-color: rgba(245, 246, 185, .95);
  box-shadow:
    0 0 0 1px rgba(35, 42, 32, .88),
    3px 4px 0 rgba(25, 30, 24, .72),
    0 14px 26px -12px rgba(145, 181, 72, .9),
    inset 0 1px 0 rgba(255, 255, 222, .2);
}

.fg-root:hover .fg-shell::before {
  animation-duration: 3.2s;
}

.fg-root:hover .fg-deco::before {
  animation-duration: 2.4s;
}

.fg-root:hover .fg-avatar {
  transform: scale(1.045);
  box-shadow:
    0 0 0 3px rgba(22, 31, 24, .82),
    0 0 0 4px rgba(239, 242, 160, .55),
    0 0 18px rgba(206, 222, 103, .54),
    inset 0 0 14px rgba(238, 249, 177, .3);
}

@keyframes radar-turn {
  to { transform: rotate(360deg); }
}

@keyframes scan-pass {
  0%, 12% { transform: translateX(-230%) skewX(-16deg); opacity: 0; }
  22% { opacity: .9; }
  62% { transform: translateX(440%) skewX(-16deg); opacity: .9; }
  74%, 100% { transform: translateX(480%) skewX(-16deg); opacity: 0; }
}

@keyframes signal-blink {
  0%, 34% { opacity: .38; }
  68%, 100% { opacity: .9; }
}

@keyframes lens-pulse {
  0%, 100% { transform: scale(.92); opacity: .42; }
  50% { transform: scale(1); opacity: .88; }
}

@keyframes glyph-steady {
  0%, 100% { transform: scale(1); opacity: .96; }
  50% { transform: scale(1.035); opacity: 1; }
}

@media (prefers-reduced-motion: reduce) {
  .fg-shell::before,
  .fg-deco::before,
  .fg-deco::after,
  .fg-avatar::before,
  .fg-glyph {
    animation: none;
  }

  .fg-shell,
  .fg-avatar {
    transition: none;
  }
}
